import { describe, expect, it } from 'vitest';
import { appendComplexU8 } from './iq';
import { mulberry32, gaussianPairFrom } from './noise';
import {
  extractWitness,
  extractWitnessFromRtl433,
  witnessAgree,
  DEFAULT_WITNESS_OPTS,
} from './skymesh-witness';
import {
  admitStation,
  buildStation,
  buildSkymeshFrame,
  SKYMESH_CACHED_ANSWER,
  SKYMESH_SCHEMA_VERSION,
  SKYMESH_GEODESIC_LENGTH,
} from './skymesh';
import { parseRtl433JsonLine } from './rtl433';
import {
  PROTOCOL69_BROADCAST_SYMBOL,
  PROTOCOL69_EXPECTED_PROJECTION,
} from '../src/protocol69';

const SAMPLE_RATE = 2_400_000;
const W_OPTS = { sampleRateHz: SAMPLE_RATE } as const;

/**
 * Deterministic synthetic ambient capture: a comb of tones (the "sky", fixed by
 * signalSeed) seen through one receiver's own noise + tiny PPM mistune (rxSeed).
 * Two stations of the SAME sky share signalSeed but differ in rxSeed. Tones sit
 * on the witness band centers (matching DEFAULT_WITNESS_OPTS.bands) so the
 * gain-invariant top-band fingerprint is stable across receivers.
 */
const WITNESS_BANDS = DEFAULT_WITNESS_OPTS.bands; // 64
function synthAmbientView(args: {
  signalSeed: number;
  rxSeed: number;
  durationSec: number;
  noiseRms: number;
  /** Per-receiver linear gain; the witness must be invariant to this. */
  gain?: number;
}): Uint8Array {
  const n = Math.max(1, Math.floor(SAMPLE_RATE * args.durationSec));
  const shapeRng = mulberry32(args.signalSeed);
  const toneCount = 4;
  const chosen: number[] = [];
  while (chosen.length < toneCount) {
    const band = Math.floor(shapeRng() * WITNESS_BANDS);
    if (!chosen.includes(band)) chosen.push(band);
  }
  const amps = chosen.map(() => 0.4 + 0.6 * shapeRng());
  const phases = chosen.map(() => 2 * Math.PI * shapeRng());
  const rxRng = mulberry32(args.rxSeed);
  const ifOffsetFrac = (rxRng() - 0.5) * 0.0005;
  const gain = args.gain ?? 1;
  const out: number[] = [];
  for (let i = 0; i < n; i++) {
    let re = 0;
    let im = 0;
    for (let t = 0; t < chosen.length; t++) {
      const frac = -0.5 + (chosen[t]! + 0.5) / WITNESS_BANDS + ifOffsetFrac;
      const w = 2 * Math.PI * frac;
      re += amps[t]! * Math.cos(w * i + phases[t]!);
      im += amps[t]! * Math.sin(w * i + phases[t]!);
    }
    if (args.noiseRms > 0) {
      const [g0, g1] = gaussianPairFrom(rxRng);
      re += args.noiseRms * g0;
      im += args.noiseRms * g1;
    }
    appendComplexU8(out, (gain * re) / toneCount, (gain * im) / toneCount);
  }
  return Uint8Array.from(out);
}

describe('skymesh witness', () => {
  it('two independent receivers of the SAME sky -> witnesses agree', () => {
    const a = synthAmbientView({ signalSeed: 6907, rxSeed: 1001, durationSec: 0.01, noiseRms: 0.05 });
    const b = synthAmbientView({ signalSeed: 6907, rxSeed: 2002, durationSec: 0.01, noiseRms: 0.05 });
    const wa = extractWitness(a, W_OPTS);
    const wb = extractWitness(b, W_OPTS);
    expect(wa.confidence).toBeGreaterThan(0);
    // Two physically distinct receivers need NOT produce a bit-identical witness
    // (that was the brittle assumption); they must AGREE under the resilient rule.
    expect(witnessAgree(wa.witness, wb.witness)).toBe(true);
  });

  it('witness is GAIN-INVARIANT: same sky, very different receiver gain -> agree', () => {
    // The real failure mode: two NESDRs off one station differ ~2 bits in absolute
    // energy. The dominant-band SET (carrier location) is invariant to gain.
    const a = synthAmbientView({ signalSeed: 7, rxSeed: 11, durationSec: 0.01, noiseRms: 0.03, gain: 1.0 });
    const b = synthAmbientView({ signalSeed: 7, rxSeed: 99, durationSec: 0.01, noiseRms: 0.03, gain: 0.25 });
    expect(witnessAgree(extractWitness(a, W_OPTS).witness, extractWitness(b, W_OPTS).witness)).toBe(true);
  });

  it('a DIFFERENT sky -> witnesses disagree', () => {
    const a = synthAmbientView({ signalSeed: 6907, rxSeed: 1001, durationSec: 0.01, noiseRms: 0.05 });
    const other = synthAmbientView({ signalSeed: 424242, rxSeed: 3003, durationSec: 0.01, noiseRms: 0.05 });
    expect(witnessAgree(extractWitness(a, W_OPTS).witness, extractWitness(other, W_OPTS).witness)).toBe(false);
  });

  it('resilience: one differing dominant band still agrees; two does not', () => {
    // Encoding is 8 bits per top band, ascending: [b0,b1,b2] -> b0<<16|b1<<8|b2.
    const base = (10 << 16) | (20 << 8) | 30;
    const oneOff = (10 << 16) | (20 << 8) | 31; // weakest band moved by 1
    const twoOff = (10 << 16) | (25 << 8) | 31; // two bands differ
    expect(witnessAgree(base, oneOff)).toBe(true);
    expect(witnessAgree(base, twoOff)).toBe(false);
  });

  it('decoded-field witness folds an rtl_433 device id; same id -> same witness', () => {
    const ev1 = parseRtl433JsonLine('{"model":"Acurite-Tower","id":1234,"channel":"A"}')!;
    const ev2 = parseRtl433JsonLine('{"model":"Acurite-Tower","id":1234,"channel":"A","temperature_C":21.7}')!;
    const ev3 = parseRtl433JsonLine('{"model":"Acurite-Tower","id":9999,"channel":"A"}')!;
    const w1 = extractWitnessFromRtl433(ev1);
    const w2 = extractWitnessFromRtl433(ev2);
    const w3 = extractWitnessFromRtl433(ev3);
    expect(w1.witness).toBe(w2.witness); // same id -> same witness (exact: decoded field)
    expect(w1.witness).not.toBe(w3.witness);
    expect(w1.confidence).toBe(1);
  });
});

describe('skymesh protocol', () => {
  const witness = 0x0a141e; // top bands [10,20,30]

  it('canonical admit (matching witness, locked) -> projection 69 + cached token', () => {
    const adm = admitStation({
      witness,
      witnessLocked: true,
      referenceWitness: witness,
      broadcastSymbol: PROTOCOL69_BROADCAST_SYMBOL,
    });
    expect(adm.admitted).toBe(true);
    expect(adm.projection).toBe(PROTOCOL69_EXPECTED_PROJECTION);
    expect(adm.state).toBe('TELEPORTED');
    expect(adm.token).toBe(SKYMESH_CACHED_ANSWER);
    expect(adm.geodesicLength).toBe(SKYMESH_GEODESIC_LENGTH);
  });

  it('no lock -> LISTENING, no token', () => {
    const adm = admitStation({ witness, witnessLocked: false, referenceWitness: witness });
    expect(adm.admitted).toBe(false);
    expect(adm.state).toBe('LISTENING');
    expect(adm.token).toBeNull();
  });

  it('MISS: a different sky (no agreement) -> DENIED, no token', () => {
    const adm = admitStation({
      witness,
      witnessLocked: true,
      referenceWitness: (1 << 16) | (2 << 8) | 3, // entirely different bands
    });
    expect(adm.admitted).toBe(false);
    expect(adm.state).toBe('DENIED');
    expect(adm.token).toBeNull();
  });

  it('TAMPER: matching witness but FORGED protocol69 key -> DENIED (fail closed)', () => {
    // Station heard the same sky (witness agrees) but presents broadcast symbol 67,
    // not 66: projection 67 XOR 7 = 64, not 69. The cryptographic gate denies.
    const adm = admitStation({
      witness,
      witnessLocked: true,
      referenceWitness: witness,
      broadcastSymbol: 67,
    });
    expect(adm.admitted).toBe(false);
    expect(adm.projection).not.toBe(PROTOCOL69_EXPECTED_PROJECTION);
    expect(adm.state).toBe('DENIED');
    expect(adm.token).toBeNull();
  });

  it('TAMPER via live foil rejection -> DENIED even if witnesses agree', () => {
    const adm = admitStation({
      witness,
      witnessLocked: true,
      referenceWitness: witness,
      foilValidated: false,
    });
    expect(adm.admitted).toBe(false);
    expect(adm.state).toBe('DENIED');
    expect(adm.token).toBeNull();
  });
});

describe('skymesh frame', () => {
  function station(
    id: string,
    witness: number,
    ref: number,
    locked = true,
    broadcastSymbol?: number,
  ) {
    const adm = admitStation({ witness, witnessLocked: locked, referenceWitness: ref, broadcastSymbol });
    return buildStation({ id, witness, witnessLocked: locked, spectrum: [0.1, 0.2], admission: adm });
  }

  it('HIT frame: both teleported, equal tokens -> match true, schema shape exact', () => {
    const w = (10 << 16) | (20 << 8) | 30;
    const a = station('station-a', w, w);
    const b = station('station-b', w, w);
    const frame = buildSkymeshFrame([a, b]);

    expect(frame.schemaVersion).toBe(SKYMESH_SCHEMA_VERSION);
    expect(frame.match).toBe(true);
    expect(frame.airGap.linkBetweenStations).toBe(false);
    expect(typeof frame.airGap.proof).toBe('string');
    expect(frame.stations).toHaveLength(2);

    for (const s of frame.stations) {
      expect(Object.keys(s).sort()).toEqual(
        [
          'geodesicLength',
          'id',
          'projection',
          'spectrum',
          'state',
          'token',
          'witness',
          'witnessLocked',
        ].sort(),
      );
    }
    expect(frame.stations.every((s) => s.token === SKYMESH_CACHED_ANSWER)).toBe(true);
    expect(frame.stations.every((s) => s.state === 'TELEPORTED')).toBe(true);
    expect(frame.stations.every((s) => s.projection === PROTOCOL69_EXPECTED_PROJECTION)).toBe(true);
    expect(Object.keys(frame).sort()).toEqual(
      ['airGap', 'match', 'schemaVersion', 'stations'].sort(),
    );
  });

  it('TAMPER frame: B heard the sky but forged the key -> B DENIED, match false', () => {
    const w = (10 << 16) | (20 << 8) | 30;
    const a = station('station-a', w, w); // legit -> TELEPORTED
    const b = station('station-b', w, w, true, 67); // same witness, forged projection -> DENIED
    const frame = buildSkymeshFrame([a, b]);
    expect(frame.match).toBe(false);
    expect(frame.stations[0]!.state).toBe('TELEPORTED');
    expect(frame.stations[1]!.state).toBe('DENIED');
    expect(frame.stations[1]!.token).toBeNull();
  });
});
